export const hasExplicitSlur = (handle: string): boolean => {
  return explicitSlurRegexes.some(
    (reg) =>
      reg.test(handle) ||
      reg.test(
        handle.replaceAll('.', '').replaceAll('-', '').replaceAll('_', ''),
      ),
  )
}
